"use strict";(self.webpackChunkai_comm_patterns=self.webpackChunkai_comm_patterns||[]).push([[1236],{910:e=>{e.exports=JSON.parse('{"tag":{"label":"workflow","permalink":"/ai-comm-patterns/docs/tags/workflow","allTagsPath":"/ai-comm-patterns/docs/tags","count":3,"items":[{"id":"collaboration/article-1764451618260","title":"AI Assisted Knowledge Generation: Can the System Document Itself?","description":"What if the biggest barrier to AI adoption in organizations isn\'t the technology itself, but our ability to create and curate the knowledge these systems need? This conversation explores a hypothesis about developing new organizational habits around knowledge management and testing a prototype system that moves seamlessly from deep discussion to structured, AI-accessible documentation.","permalink":"/ai-comm-patterns/docs/collaboration/article-1764451618260"},{"id":"experimentation/article_suggestions","title":"Article Suggestions Workflow","description":"This repository includes an automated AI Content Research Agent that helps generate article suggestions based on the site\u2019s current content and external research.","permalink":"/ai-comm-patterns/docs/experimentation/article_suggestions"},{"id":"collaboration/initial_prompt","title":"Initial Prompt - Concept","description":"My goal with this knowledge management site is to build and co-create all of the details with AI as well as Human collaborators.   In my initial experiment, I\'m working with Claude to create a sort of working agreement together on how we would develop knowledge, and then create a workflow that we can use to create and post markdown files on the knowledge site.","permalink":"/ai-comm-patterns/docs/collaboration/initial_prompt"}],"unlisted":false}}')}}]);